package main

import "codeagent-wrapper/internal/bootstrap"

func main() {
	bootstrap.Main()
}

package cli

import (
	"go/parser"
	"go/token"
	"path/filepath"
	"slices"
	"strings"
	"testing"
)

func TestMainImportsBootstrapDirectly(t *testing.T) {
	root := projectRoot(t)
	path := filepath.Join(root, "cmd", "codeagent-wrapper", "main.go")
	imports := parseImports(t, path)
	if len(imports) != 1 || !slices.Contains(imports, "codeagent-wrapper/internal/bootstrap") {
		t.Fatalf("%s imports = %v, want [codeagent-wrapper/internal/bootstrap]", path, imports)
	}
}

func TestBootstrapComposesAppAndCLIAdapter(t *testing.T) {
	root := projectRoot(t)
	path := filepath.Join(root, "internal", "bootstrap", "bootstrap.go")
	imports := parseImports(t, path)
	if len(imports) != 3 ||
		!slices.Contains(imports, "os") ||
		!slices.Contains(imports, "codeagent-wrapper/internal/adapter/cli") ||
		!slices.Contains(imports, "codeagent-wrapper/internal/app") {
		t.Fatalf("%s imports = %v, want os + internal/adapter/cli + internal/app", path, imports)
	}
}

func TestCLIAdapterDoesNotImportAppOrBootstrap(t *testing.T) {
	root := projectRoot(t)
	files, err := filepath.Glob(filepath.Join(root, "internal", "adapter", "cli", "*.go"))
	if err != nil {
		t.Fatalf("Glob(): %v", err)
	}

	for _, path := range files {
		base := filepath.Base(path)
		if strings.HasSuffix(base, "_test.go") {
			continue
		}

		imports := parseImports(t, path)
		for _, imp := range imports {
			switch imp {
			case "codeagent-wrapper/internal/app", "codeagent-wrapper/internal/bootstrap":
				t.Fatalf("%s imports forbidden entry package %q", base, imp)
			}
		}
	}
}

func parseImports(t *testing.T, path string) []string {
	t.Helper()

	fset := token.NewFileSet()
	file, err := parser.ParseFile(fset, path, nil, parser.ImportsOnly)
	if err != nil {
		t.Fatalf("ParseFile(%q): %v", path, err)
	}

	imports := make([]string, 0, len(file.Imports))
	for _, imp := range file.Imports {
		imports = append(imports, strings.Trim(imp.Path.Value, `"`))
	}
	return imports
}

func projectRoot(t *testing.T) string {
	t.Helper()

	root, err := filepath.Abs(filepath.Join("..", "..", ".."))
	if err != nil {
		t.Fatalf("Abs(): %v", err)
	}
	return root
}

package cli

import (
	"errors"
	"fmt"

	"github.com/spf13/cobra"
	"github.com/spf13/pflag"
)

type ExitError struct {
	Code int
}

func (e ExitError) Error() string {
	return fmt.Sprintf("exit %d", e.Code)
}

type Options struct {
	Backend         string
	Model           string
	ReasoningEffort string
	Agent           string
	PromptFile      string
	Output          string
	Skills          string
	SkipPermissions bool
	Worktree        bool

	Parallel   bool
	FullOutput bool

	Cleanup    bool
	Version    bool
	ConfigFile string
}

type RootDeps struct {
	Name    func() string
	Version func() string
	Cleanup func() int
	Execute func(cmd *cobra.Command, args []string, opts *Options, name string) error
}

func Run(args []string, deps RootDeps) int {
	cmd := NewRootCommand(deps)
	cmd.SetArgs(args)
	if err := cmd.Execute(); err != nil {
		var ee ExitError
		if errors.As(err, &ee) {
			return ee.Code
		}
		return 1
	}
	return 0
}

func NewRootCommand(deps RootDeps) *cobra.Command {
	name := deps.Name()
	opts := &Options{}

	cmd := &cobra.Command{
		Use:           fmt.Sprintf("%s [flags] <task>|resume <session_id> <task> [workdir]", name),
		Short:         "Go wrapper for AI CLI backends",
		SilenceErrors: true,
		SilenceUsage:  true,
		Args:          cobra.ArbitraryArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			if opts.Version {
				fmt.Printf("%s version %s\n", name, deps.Version())
				return nil
			}
			if opts.Cleanup {
				code := deps.Cleanup()
				if code == 0 {
					return nil
				}
				return ExitError{Code: code}
			}
			return deps.Execute(cmd, args, opts, name)
		},
	}
	cmd.CompletionOptions.DisableDefaultCmd = true

	AddRootFlags(cmd.Flags(), opts)
	cmd.AddCommand(newVersionCommand(name, deps.Version), newCleanupCommand(deps.Cleanup))

	return cmd
}

func AddRootFlags(fs *pflag.FlagSet, opts *Options) {
	fs.StringVar(&opts.ConfigFile, "config", "", "Config file path (default: $HOME/.codeagent/config.*)")
	fs.BoolVarP(&opts.Version, "version", "v", false, "Print version and exit")
	fs.BoolVar(&opts.Cleanup, "cleanup", false, "Clean up old logs and exit")

	fs.BoolVar(&opts.Parallel, "parallel", false, "Run tasks in parallel (config from stdin)")
	fs.BoolVar(&opts.FullOutput, "full-output", false, "Parallel mode: include full task output (legacy)")

	fs.StringVar(&opts.Backend, "backend", "codex", "Backend to use (codex, claude, gemini, opencode)")
	fs.StringVar(&opts.Model, "model", "", "Model override")
	fs.StringVar(&opts.ReasoningEffort, "reasoning-effort", "", "Reasoning effort (backend-specific)")
	fs.StringVar(&opts.Agent, "agent", "", "Agent preset name (from ~/.codeagent/models.json)")
	fs.StringVar(&opts.PromptFile, "prompt-file", "", "Prompt file path")
	fs.StringVar(&opts.Output, "output", "", "Write structured JSON output to file")
	fs.StringVar(&opts.Skills, "skills", "", "Comma-separated skill names for spec injection")

	fs.BoolVar(&opts.SkipPermissions, "skip-permissions", false, "Skip permissions prompts (also via CODEAGENT_SKIP_PERMISSIONS)")
	fs.BoolVar(&opts.SkipPermissions, "dangerously-skip-permissions", false, "Alias for --skip-permissions")
	fs.BoolVar(&opts.Worktree, "worktree", false, "Execute in a new git worktree (auto-generates task ID)")
}

func newVersionCommand(name string, version func() string) *cobra.Command {
	return &cobra.Command{
		Use:           "version",
		Short:         "Print version and exit",
		SilenceErrors: true,
		SilenceUsage:  true,
		RunE: func(cmd *cobra.Command, args []string) error {
			fmt.Printf("%s version %s\n", name, version())
			return nil
		},
	}
}

func newCleanupCommand(cleanup func() int) *cobra.Command {
	return &cobra.Command{
		Use:           "cleanup",
		Short:         "Clean up old logs and exit",
		SilenceErrors: true,
		SilenceUsage:  true,
		RunE: func(cmd *cobra.Command, args []string) error {
			code := cleanup()
			if code == 0 {
				return nil
			}
			return ExitError{Code: code}
		},
	}
}

package cli

import (
	"fmt"

	config "codeagent-wrapper/internal/config"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

type ExecuteDeps struct {
	NewViper          func(string) (*viper.Viper, error)
	LogError          func(string)
	LogInfo           func(string)
	BuildSingleConfig func(cmd *cobra.Command, args []string, rawArgv []string, opts *Options, v *viper.Viper) (*config.Config, error)
	RunParallel       func(cmd *cobra.Command, args []string, opts *Options, v *viper.Viper, name string) int
	RunSingle         func(cfg *config.Config, name string) int
}

func ExecuteMode(cmd *cobra.Command, args []string, rawArgv []string, opts *Options, name string, deps ExecuteDeps) int {
	v, err := deps.NewViper(opts.ConfigFile)
	if err != nil {
		deps.LogError(err.Error())
		return 1
	}

	if opts.Parallel {
		return deps.RunParallel(cmd, args, opts, v, name)
	}

	deps.LogInfo("Script started")

	cfg, err := deps.BuildSingleConfig(cmd, args, rawArgv, opts, v)
	if err != nil {
		deps.LogError(err.Error())
		return 1
	}
	deps.LogInfo(fmt.Sprintf("Parsed args: mode=%s, task_len=%d, backend=%s", cfg.Mode, len(cfg.Task), cfg.Backend))
	return deps.RunSingle(cfg, name)
}

package cli

import (
	"errors"
	"testing"

	config "codeagent-wrapper/internal/config"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

func TestExecuteMode_ParallelBranch(t *testing.T) {
	opts := &Options{ConfigFile: "cfg", Parallel: true}
	cmd := &cobra.Command{}
	got := ExecuteMode(cmd, []string{"ignored"}, []string{"--parallel"}, opts, "wrapper", ExecuteDeps{
		NewViper: func(path string) (*viper.Viper, error) {
			if path != "cfg" {
				t.Fatalf("path = %q, want cfg", path)
			}
			return viper.New(), nil
		},
		LogError: func(string) {},
		LogInfo:  func(string) {},
		BuildSingleConfig: func(*cobra.Command, []string, []string, *Options, *viper.Viper) (*config.Config, error) {
			t.Fatal("BuildSingleConfig should not be called")
			return nil, nil
		},
		RunParallel: func(gotCmd *cobra.Command, gotArgs []string, gotOpts *Options, gotV *viper.Viper, gotName string) int {
			if gotCmd != cmd || gotOpts != opts || gotV == nil || gotName != "wrapper" || len(gotArgs) != 1 {
				t.Fatalf("unexpected parallel args")
			}
			return 7
		},
		RunSingle: func(*config.Config, string) int {
			t.Fatal("RunSingle should not be called")
			return 0
		},
	})
	if got != 7 {
		t.Fatalf("ExecuteMode() = %d, want 7", got)
	}
}

func TestExecuteMode_SingleBranch(t *testing.T) {
	opts := &Options{}
	cmd := &cobra.Command{}
	var infos []string
	got := ExecuteMode(cmd, []string{"task"}, []string{"task"}, opts, "wrapper", ExecuteDeps{
		NewViper: func(string) (*viper.Viper, error) { return viper.New(), nil },
		LogError: func(string) {},
		LogInfo:  func(msg string) { infos = append(infos, msg) },
		BuildSingleConfig: func(*cobra.Command, []string, []string, *Options, *viper.Viper) (*config.Config, error) {
			return &config.Config{Mode: "new", Task: "task", Backend: "codex"}, nil
		},
		RunParallel: func(*cobra.Command, []string, *Options, *viper.Viper, string) int {
			t.Fatal("RunParallel should not be called")
			return 0
		},
		RunSingle: func(cfg *config.Config, name string) int {
			if cfg.Task != "task" || name != "wrapper" {
				t.Fatalf("cfg=%+v name=%q", cfg, name)
			}
			return 3
		},
	})
	if got != 3 {
		t.Fatalf("ExecuteMode() = %d, want 3", got)
	}
	if len(infos) != 2 {
		t.Fatalf("LogInfo count = %d, want 2", len(infos))
	}
}

func TestExecuteMode_ConfigError(t *testing.T) {
	opts := &Options{ConfigFile: "bad"}
	var gotErr string
	got := ExecuteMode(&cobra.Command{}, nil, nil, opts, "wrapper", ExecuteDeps{
		NewViper: func(string) (*viper.Viper, error) { return nil, errors.New("boom") },
		LogError: func(msg string) { gotErr = msg },
		LogInfo:  func(string) {},
		BuildSingleConfig: func(*cobra.Command, []string, []string, *Options, *viper.Viper) (*config.Config, error) {
			return nil, nil
		},
		RunParallel: func(*cobra.Command, []string, *Options, *viper.Viper, string) int { return 0 },
		RunSingle:   func(*config.Config, string) int { return 0 },
	})
	if got != 1 || gotErr != "boom" {
		t.Fatalf("ExecuteMode() = %d, gotErr=%q", got, gotErr)
	}
}

package cli

import (
	"fmt"
	"io"
	"os"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

type ParallelDeps[Plan any] struct {
	BuildPlan func(cmd *cobra.Command, opts *Options, v *viper.Viper) (Plan, error)
	RunPlan   func(plan Plan) (string, int, error)
}

func ExecuteParallelMode[Plan any](cmd *cobra.Command, args []string, opts *Options, v *viper.Viper, name string, deps ParallelDeps[Plan]) int {
	if len(args) > 0 {
		WriteParallelModeArgumentError(stderrWriter(), name)
		return 1
	}

	if cmd.Flags().Changed("agent") || cmd.Flags().Changed("prompt-file") || cmd.Flags().Changed("reasoning-effort") || cmd.Flags().Changed("skills") {
		WriteParallelModeFlagError(stderrWriter())
		return 1
	}

	plan, err := deps.BuildPlan(cmd, opts, v)
	if err != nil {
		fmt.Fprintf(stderrWriter(), "ERROR: %v\n", err)
		return 1
	}

	stdout, exitCode, err := deps.RunPlan(plan)
	if err != nil {
		fmt.Fprintf(stderrWriter(), "ERROR: %v\n", err)
		return 1
	}
	return EmitParallelResult(stdoutWriter(), stdout, exitCode)
}

var stdoutWriter = func() io.Writer { return os.Stdout }
var stderrWriter = func() io.Writer { return os.Stderr }

package cli

import (
	"fmt"
	"io"
	"strings"

	runtaskset "codeagent-wrapper/internal/application/runtaskset"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

type ParallelInputDeps struct {
	StdinReader        io.Reader
	DefaultBackendName string
	ResolveMaxWorkers  func(*viper.Viper) int
}

func BuildParallelInput(cmd *cobra.Command, opts *Options, v *viper.Viper, deps ParallelInputDeps) (runtaskset.BuildInput, error) {
	backendName := deps.DefaultBackendName
	if cmd.Flags().Changed("backend") {
		backendName = strings.TrimSpace(opts.Backend)
		if backendName == "" {
			return runtaskset.BuildInput{}, fmt.Errorf("--backend flag requires a value")
		}
	} else if val := strings.TrimSpace(v.GetString("backend")); val != "" {
		backendName = val
	}

	model := ""
	if cmd.Flags().Changed("model") {
		model = strings.TrimSpace(opts.Model)
		if model == "" {
			return runtaskset.BuildInput{}, fmt.Errorf("--model flag requires a value")
		}
	} else {
		model = strings.TrimSpace(v.GetString("model"))
	}

	summaryOnly := !opts.FullOutput
	if !cmd.Flags().Changed("full-output") && v.IsSet("full-output") {
		summaryOnly = !v.GetBool("full-output")
	}

	outputPath := ""
	if cmd.Flags().Changed("output") {
		outputPath = strings.TrimSpace(opts.Output)
		if outputPath == "" {
			return runtaskset.BuildInput{}, fmt.Errorf("--output flag requires a value")
		}
	} else if val := strings.TrimSpace(v.GetString("output")); val != "" {
		outputPath = val
	}

	skipChanged := cmd.Flags().Changed("skip-permissions") || cmd.Flags().Changed("dangerously-skip-permissions")
	skipPermissions := false
	if skipChanged {
		skipPermissions = opts.SkipPermissions
	} else {
		skipPermissions = v.GetBool("skip-permissions")
	}

	data, err := io.ReadAll(deps.StdinReader)
	if err != nil {
		return runtaskset.BuildInput{}, fmt.Errorf("failed to read stdin: %w", err)
	}

	return runtaskset.BuildInput{
		BackendName:     backendName,
		Model:           model,
		OutputPath:      outputPath,
		SummaryOnly:     summaryOnly,
		SkipPermissions: skipPermissions,
		StdinData:       data,
		MaxWorkers:      deps.ResolveMaxWorkers(v),
	}, nil
}

package cli

import (
	"bytes"
	"testing"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

func TestBuildParallelInputUsesCLIAndViperValues(t *testing.T) {
	opts := &Options{}
	cmd := &cobra.Command{}
	AddRootFlags(cmd.Flags(), opts)
	opts.Backend = "claude"
	opts.Model = "sonnet"
	opts.Output = "out.json"
	opts.FullOutput = true
	opts.SkipPermissions = true
	cmd.Flags().Lookup("backend").Changed = true
	cmd.Flags().Lookup("model").Changed = true
	cmd.Flags().Lookup("output").Changed = true
	cmd.Flags().Lookup("full-output").Changed = true
	cmd.Flags().Lookup("skip-permissions").Changed = true

	v := viper.New()
	got, err := BuildParallelInput(cmd, opts, v, ParallelInputDeps{
		StdinReader:        bytes.NewBufferString("task stream"),
		DefaultBackendName: "codex",
		ResolveMaxWorkers:  func(*viper.Viper) int { return 7 },
	})
	if err != nil {
		t.Fatalf("BuildParallelInput() error = %v", err)
	}

	if got.BackendName != "claude" || got.Model != "sonnet" || got.OutputPath != "out.json" || got.SummaryOnly || !got.SkipPermissions || got.MaxWorkers != 7 || string(got.StdinData) != "task stream" {
		t.Fatalf("BuildParallelInput() = %#v", got)
	}
}

func TestBuildParallelInputFallsBackToViper(t *testing.T) {
	opts := &Options{}
	cmd := &cobra.Command{}
	AddRootFlags(cmd.Flags(), opts)

	v := viper.New()
	v.Set("backend", "gemini")
	v.Set("model", "pro")
	v.Set("output", "parallel.json")
	v.Set("full-output", true)
	v.Set("skip-permissions", true)

	got, err := BuildParallelInput(cmd, opts, v, ParallelInputDeps{
		StdinReader:        bytes.NewBuffer(nil),
		DefaultBackendName: "codex",
		ResolveMaxWorkers:  func(*viper.Viper) int { return 10 },
	})
	if err != nil {
		t.Fatalf("BuildParallelInput() error = %v", err)
	}

	if got.BackendName != "gemini" || got.Model != "pro" || got.OutputPath != "parallel.json" || got.SummaryOnly || !got.SkipPermissions || got.MaxWorkers != 10 {
		t.Fatalf("BuildParallelInput() = %#v", got)
	}
}

package cli

import (
	"bytes"
	"errors"
	"io"
	"strings"
	"testing"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

type bufferWriter struct{ bytes.Buffer }

func TestExecuteParallelMode_PositionalArgsRejected(t *testing.T) {
	stdout := &bufferWriter{}
	stderr := &bufferWriter{}
	restoreStdout := stdoutWriter
	restoreStderr := stderrWriter
	stdoutWriter = func() io.Writer { return stdout }
	stderrWriter = func() io.Writer { return stderr }
	defer func() {
		stdoutWriter = restoreStdout
		stderrWriter = restoreStderr
	}()

	got := ExecuteParallelMode[int](&cobra.Command{}, []string{"bad"}, &Options{}, viper.New(), "wrapper", ParallelDeps[int]{})
	if got != 1 || !strings.Contains(stderr.String(), "no positional arguments") {
		t.Fatalf("got=%d stderr=%q", got, stderr.String())
	}
}

func TestExecuteParallelMode_BuildAndRun(t *testing.T) {
	stdout := &bufferWriter{}
	stderr := &bufferWriter{}
	restoreStdout := stdoutWriter
	restoreStderr := stderrWriter
	stdoutWriter = func() io.Writer { return stdout }
	stderrWriter = func() io.Writer { return stderr }
	defer func() {
		stdoutWriter = restoreStdout
		stderrWriter = restoreStderr
	}()

	cmd := &cobra.Command{}
	cmd.Flags().String("backend", "", "")
	opts := &Options{}
	got := ExecuteParallelMode(cmd, nil, opts, viper.New(), "wrapper", ParallelDeps[int]{
		BuildPlan: func(*cobra.Command, *Options, *viper.Viper) (int, error) { return 42, nil },
		RunPlan: func(plan int) (string, int, error) {
			if plan != 42 {
				t.Fatalf("plan=%d", plan)
			}
			return "summary", 7, nil
		},
	})
	if got != 7 || stdout.String() != "summary\n" || stderr.String() != "" {
		t.Fatalf("got=%d stdout=%q stderr=%q", got, stdout.String(), stderr.String())
	}
}

func TestExecuteParallelMode_RunError(t *testing.T) {
	stdout := &bufferWriter{}
	stderr := &bufferWriter{}
	restoreStdout := stdoutWriter
	restoreStderr := stderrWriter
	stdoutWriter = func() io.Writer { return stdout }
	stderrWriter = func() io.Writer { return stderr }
	defer func() {
		stdoutWriter = restoreStdout
		stderrWriter = restoreStderr
	}()

	got := ExecuteParallelMode[int](&cobra.Command{}, nil, &Options{}, viper.New(), "wrapper", ParallelDeps[int]{
		BuildPlan: func(*cobra.Command, *Options, *viper.Viper) (int, error) { return 1, nil },
		RunPlan:   func(int) (string, int, error) { return "", 0, errors.New("boom") },
	})
	if got != 1 || !strings.Contains(stderr.String(), "ERROR: boom") {
		t.Fatalf("got=%d stderr=%q", got, stderr.String())
	}
}

package cli

import (
	"fmt"
	"strings"

	config "codeagent-wrapper/internal/config"

	"github.com/spf13/cobra"
	"github.com/spf13/viper"
)

const defaultWorkdir = "."

func ParseSingleConfig(rawArgv []string) (*config.Config, error) {
	opts := &Options{}
	cmd := &cobra.Command{SilenceErrors: true, SilenceUsage: true, Args: cobra.ArbitraryArgs}
	AddRootFlags(cmd.Flags(), opts)

	if err := cmd.ParseFlags(rawArgv); err != nil {
		return nil, err
	}
	args := cmd.Flags().Args()

	v, err := config.NewViper(opts.ConfigFile)
	if err != nil {
		return nil, err
	}

	return BuildSingleConfig(cmd, args, rawArgv, opts, v)
}

func BuildSingleConfig(cmd *cobra.Command, args []string, rawArgv []string, opts *Options, v *viper.Viper) (*config.Config, error) {
	backendName := "codex"
	model := ""
	reasoningEffort := ""
	agentName := ""
	promptFile := ""
	promptFileExplicit := false
	outputPath := ""
	yolo := false

	if cmd.Flags().Changed("agent") {
		agentName = strings.TrimSpace(opts.Agent)
		if agentName == "" {
			return nil, fmt.Errorf("--agent flag requires a value")
		}
		if err := config.ValidateAgentName(agentName); err != nil {
			return nil, fmt.Errorf("--agent flag invalid value: %w", err)
		}
	} else {
		agentName = strings.TrimSpace(v.GetString("agent"))
		if agentName != "" {
			if err := config.ValidateAgentName(agentName); err != nil {
				return nil, fmt.Errorf("--agent flag invalid value: %w", err)
			}
		}
	}

	var resolvedBackend, resolvedModel, resolvedPromptFile, resolvedReasoning string
	var resolvedAllowedTools, resolvedDisallowedTools []string
	if agentName != "" {
		var resolvedYolo bool
		var err error
		resolvedBackend, resolvedModel, resolvedPromptFile, resolvedReasoning, _, _, resolvedYolo, resolvedAllowedTools, resolvedDisallowedTools, err = config.ResolveAgentConfig(agentName)
		if err != nil {
			return nil, fmt.Errorf("failed to resolve agent %q: %w", agentName, err)
		}
		yolo = resolvedYolo
	}

	if cmd.Flags().Changed("prompt-file") {
		promptFile = strings.TrimSpace(opts.PromptFile)
		if promptFile == "" {
			return nil, fmt.Errorf("--prompt-file flag requires a value")
		}
		promptFileExplicit = true
	} else if val := strings.TrimSpace(v.GetString("prompt-file")); val != "" {
		promptFile = val
		promptFileExplicit = true
	} else {
		promptFile = resolvedPromptFile
	}

	if cmd.Flags().Changed("output") {
		outputPath = strings.TrimSpace(opts.Output)
		if outputPath == "" {
			return nil, fmt.Errorf("--output flag requires a value")
		}
	} else if val := strings.TrimSpace(v.GetString("output")); val != "" {
		outputPath = val
	}

	agentFlagChanged := cmd.Flags().Changed("agent")
	backendFlagChanged := cmd.Flags().Changed("backend")
	if backendFlagChanged {
		backendName = strings.TrimSpace(opts.Backend)
		if backendName == "" {
			return nil, fmt.Errorf("--backend flag requires a value")
		}
	}

	switch {
	case agentFlagChanged && backendFlagChanged && LastFlagIndex(rawArgv, "agent") > LastFlagIndex(rawArgv, "backend"):
		backendName = resolvedBackend
	case !backendFlagChanged && agentName != "":
		backendName = resolvedBackend
	case !backendFlagChanged:
		if val := strings.TrimSpace(v.GetString("backend")); val != "" {
			backendName = val
		}
	}

	modelFlagChanged := cmd.Flags().Changed("model")
	if modelFlagChanged {
		model = strings.TrimSpace(opts.Model)
		if model == "" {
			return nil, fmt.Errorf("--model flag requires a value")
		}
	}

	switch {
	case agentFlagChanged && modelFlagChanged && LastFlagIndex(rawArgv, "agent") > LastFlagIndex(rawArgv, "model"):
		model = strings.TrimSpace(resolvedModel)
	case !modelFlagChanged && agentName != "":
		model = strings.TrimSpace(resolvedModel)
	case !modelFlagChanged:
		model = strings.TrimSpace(v.GetString("model"))
	}

	if cmd.Flags().Changed("reasoning-effort") {
		reasoningEffort = strings.TrimSpace(opts.ReasoningEffort)
		if reasoningEffort == "" {
			return nil, fmt.Errorf("--reasoning-effort flag requires a value")
		}
	} else if val := strings.TrimSpace(v.GetString("reasoning-effort")); val != "" {
		reasoningEffort = val
	} else if agentName != "" {
		reasoningEffort = strings.TrimSpace(resolvedReasoning)
	}

	skipChanged := cmd.Flags().Changed("skip-permissions") || cmd.Flags().Changed("dangerously-skip-permissions")
	skipPermissions := false
	if skipChanged {
		skipPermissions = opts.SkipPermissions
	} else {
		skipPermissions = v.GetBool("skip-permissions")
	}

	if len(args) == 0 {
		return nil, fmt.Errorf("task required")
	}

	var skills []string
	if cmd.Flags().Changed("skills") {
		for _, s := range strings.Split(opts.Skills, ",") {
			s = strings.TrimSpace(s)
			if s != "" {
				skills = append(skills, s)
			}
		}
	}

	cfg := &config.Config{
		WorkDir:            defaultWorkdir,
		Backend:            backendName,
		Agent:              agentName,
		PromptFile:         promptFile,
		PromptFileExplicit: promptFileExplicit,
		OutputPath:         outputPath,
		SkipPermissions:    skipPermissions,
		Yolo:               yolo,
		Model:              model,
		ReasoningEffort:    reasoningEffort,
		MaxParallelWorkers: config.ResolveMaxParallelWorkers(),
		AllowedTools:       resolvedAllowedTools,
		DisallowedTools:    resolvedDisallowedTools,
		Skills:             skills,
		Worktree:           opts.Worktree,
	}

	if args[0] == "resume" {
		if len(args) < 3 {
			return nil, fmt.Errorf("resume mode requires: resume <session_id> <task>")
		}
		cfg.Mode = "resume"
		cfg.SessionID = strings.TrimSpace(args[1])
		if cfg.SessionID == "" {
			return nil, fmt.Errorf("resume mode requires non-empty session_id")
		}
		cfg.Task = args[2]
		cfg.ExplicitStdin = args[2] == "-"
		if len(args) > 3 {
			if args[3] == "-" {
				return nil, fmt.Errorf("invalid workdir: '-' is not a valid directory path")
			}
			cfg.WorkDir = args[3]
		}
		return cfg, nil
	}

	cfg.Mode = "new"
	cfg.Task = args[0]
	cfg.ExplicitStdin = args[0] == "-"
	if len(args) > 1 {
		if args[1] == "-" {
			return nil, fmt.Errorf("invalid workdir: '-' is not a valid directory path")
		}
		cfg.WorkDir = args[1]
	}
	return cfg, nil
}

func LastFlagIndex(argv []string, name string) int {
	if len(argv) == 0 {
		return -1
	}
	name = strings.TrimSpace(name)
	if name == "" {
		return -1
	}

	needle := "--" + name
	prefix := needle + "="
	last := -1
	for i, arg := range argv {
		if arg == needle || strings.HasPrefix(arg, prefix) {
			last = i
		}
	}
	return last
}

