	defer func() {
		if r := recover(); r != nil {
			logWarn(fmt.Sprintf("cleanupOldLogs panic: %v", r))
		}
	}()
	if _, err := cleanupLogsFn(); err != nil {
		logWarn(fmt.Sprintf("cleanupOldLogs error: %v", err))
	}
}

func scheduleStartupCleanup() {
	if !startupCleanupAsync {
		runStartupCleanup()
		return
	}
	if cleanupLogsFn == nil {
		return
	}
	fn := cleanupLogsFn
	go func() {
		defer func() {
			if r := recover(); r != nil {
				logWarn(fmt.Sprintf("cleanupOldLogs panic: %v", r))
			}
		}()
		if _, err := fn(); err != nil {
			logWarn(fmt.Sprintf("cleanupOldLogs error: %v", err))
		}
	}()
}

