		StdoutPlan: []fakeStdoutEvent{
			{Data: fmt.Sprintf(`{"type":"thread.started","thread_id":"%s"}`+"\n", threadID)},
		},
		KeepStdoutOpen:      true,
		BlockWait:           true,
		ReleaseWaitOnKill:   true,
