		env["GOOGLE_GEMINI_BASE_URL"] = baseURL
	}
	if apiKey != "" {
		env["GEMINI_API_KEY"] = apiKey
	}
	return env
}
func (GeminiBackend) BuildArgs(cfg *config.Config, targetArg string) []string {
