		},
		{
			name:      "both empty",
			baseURL:   "",
			apiKey:    "",
			expectNil: true,
		},
		{
			name:      "whitespace only",
			baseURL:   "   ",
			apiKey:    "  ",
			expectNil: true,
		},
	}

